import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const fmt = (n) => {
    if (!n || n === 0) return '0';
    if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
    return String(n);
};

const RecapSection = ({ personal, group }) => {
    const [expanded, setExpanded] = useState(false);

    const bestPost = personal?.best_post;
    const mostActive = group?.most_active_writer;
    const mostReacted = group?.most_reacted_post;

    return (
        <div className="dashboard-recap">
            <div className="dashboard-stat-row" onClick={() => setExpanded((v) => !v)}>
                <span className="dashboard-stat-line">
                    <strong>{personal?.posts_written || 0}</strong> posts
                    {' · '}
                    <strong>{fmt(personal?.total_words)}</strong> words
                    {' · '}
                    <strong>{fmt(personal?.reactions_received)}</strong> reactions
                    {' · '}
                    <strong>{fmt(personal?.views_received)}</strong> views
                </span>

                <button className={`dashboard-recap-expand ${expanded ? 'is-expanded' : ''}`}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none">
                        <path d="M6 9L12 15L18 9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                </button>
            </div>

            <AnimatePresence>
                {expanded && (
                    <motion.div
                        className="dashboard-recap-details"
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.25, ease: 'easeOut' }}
                    >
                        <div className="dashboard-recap-details-inner">
                            {bestPost && bestPost.journal_id && (
                                <div className="dashboard-recap-detail">
                                    <span className="dashboard-recap-detail-heading">Your best post</span>
                                    <p className="dashboard-recap-detail-text">
                                        {bestPost.title || 'Untitled'} — {bestPost.reaction_count || 0} reactions
                                    </p>
                                </div>
                            )}

                            <div className="dashboard-recap-detail">
                                <span className="dashboard-recap-detail-heading">Community</span>
                                <p className="dashboard-recap-detail-text">
                                    {group?.total_posts || 0} posts written this week
                                </p>
                            </div>

                            {mostActive && mostActive.name && (
                                <div className="dashboard-recap-detail">
                                    <span className="dashboard-recap-detail-heading">Most active writer</span>
                                    <div className="dashboard-recap-detail-user">
                                        <img
                                            src={mostActive.avatar || '/assets/profile.jpg'}
                                            alt={mostActive.name}
                                            className="dashboard-recap-detail-avatar"
                                        />
                                        <span className="dashboard-recap-detail-text">
                                            {mostActive.name} — {mostActive.post_count} posts
                                        </span>
                                    </div>
                                </div>
                            )}

                            {mostReacted && mostReacted.title && (
                                <div className="dashboard-recap-detail">
                                    <span className="dashboard-recap-detail-heading">Most reacted post</span>
                                    <div className="dashboard-recap-detail-user">
                                        <img
                                            src={mostReacted.author_avatar || '/assets/profile.jpg'}
                                            alt={mostReacted.author_name}
                                            className="dashboard-recap-detail-avatar"
                                        />
                                        <span className="dashboard-recap-detail-text">
                                            {mostReacted.title} by {mostReacted.author_name} — {mostReacted.reaction_count || 0} reactions
                                        </span>
                                    </div>
                                </div>
                            )}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default RecapSection;

import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { motion, AnimatePresence } from 'framer-motion';
import { getWeeklyRecap, getTodaysPrompt, getPromptResponses } from '../../../API/Api';
import { useAuth } from '../../Context/useAuth';
import useStreakData from '../Streak/useStreakData';
import StreakBadge from '../Streak/StreakBadge';
import RecapSection from './RecapSection';
import PromptSection from './PromptSection';
import './DashboardBriefing.css';

const getWeekKey = () => {
    const now = new Date();
    const day = now.getUTCDay();
    const diff = day === 0 ? 6 : day - 1;
    const monday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - diff));
    return `recap-dismissed-${monday.toISOString().slice(0, 10)}`;
};

const formatDate = () => {
    return new Date().toLocaleDateString('en-US', {
        weekday: 'long',
        month: 'long',
        day: 'numeric',
    });
};

const DashboardBriefing = ({ onWriteResponse }) => {
    const { session, user } = useAuth();
    const weekKey = getWeekKey();

    const [recapDismissed, setRecapDismissed] = useState(() => {
        try { return localStorage.getItem(weekKey) === 'true'; }
        catch { return false; }
    });

    // ─── Data fetching ───

    const { data: recapData, isLoading: recapLoading } = useQuery({
        queryKey: ['weeklyRecap', session?.access_token],
        queryFn: () => getWeeklyRecap(session?.access_token),
        enabled: !!session?.access_token && !recapDismissed,
        staleTime: 1000 * 60 * 10,
        refetchOnWindowFocus: false,
    });

    const { data: prompt, isLoading: promptLoading } = useQuery({
        queryKey: ['todaysPrompt'],
        queryFn: getTodaysPrompt,
        staleTime: 1000 * 60 * 30,
        refetchOnWindowFocus: false,
    });

    const { data: responsesData } = useQuery({
        queryKey: ['promptResponses', prompt?.id],
        queryFn: () => getPromptResponses(prompt.id),
        enabled: !!prompt?.id,
        staleTime: 1000 * 60 * 5,
        refetchOnWindowFocus: false,
    });

    const { data: streakData } = useStreakData(user?.id);

    // ─── Derived state ───

    const recap = recapData?.recap;
    const personal = recap?.personal || {};
    const group = recap?.group || {};

    const hasRecap = !recapDismissed && !recapLoading && recap &&
        (personal.posts_written > 0 || group.total_posts > 0);
    const hasPrompt = !promptLoading && !!prompt;

    // Nothing to show
    if (!hasRecap && !hasPrompt) return null;

    const handleDismissRecap = (e) => {
        e.stopPropagation();
        try { localStorage.setItem(weekKey, 'true'); }
        catch { /* no-op */ }
        setRecapDismissed(true);
    };

    const streakCount = streakData?.current_streak || 0;

    return (
        <AnimatePresence>
            <motion.div
                className="dashboard-briefing"
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -15, transition: { duration: 0.25 } }}
                transition={{ duration: 0.35, ease: 'easeOut' }}
                key="dashboard-briefing"
            >
                <div className="dashboard-briefing-header">
                    <div className="dashboard-briefing-header-left">
                        <span className="dashboard-briefing-title">Today</span>
                        <span className="dashboard-briefing-date">{formatDate()}</span>
                        {streakCount > 0 && <StreakBadge count={streakCount} size={14} />}
                    </div>
                    {hasRecap && (
                        <button
                            className="dashboard-briefing-dismiss"
                            onClick={handleDismissRecap}
                            title="Dismiss recap"
                        >
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                                <path d="M18 6L6 18M6 6L18 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
                            </svg>
                        </button>
                    )}
                </div>

                <div className="dashboard-briefing-body">
                    {hasRecap && (
                        <RecapSection personal={personal} group={group} />
                    )}

                    {hasRecap && hasPrompt && (
                        <div className="dashboard-divider" />
                    )}

                    {hasPrompt && (
                        <PromptSection
                            prompt={prompt}
                            responsesData={responsesData}
                            onWriteResponse={onWriteResponse}
                        />
                    )}
                </div>
            </motion.div>
        </AnimatePresence>
    );
};

export default DashboardBriefing;

