/* ─── Dashboard Briefing ─── */

.dashboard-briefing {
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    border-left: 3px solid var(--accent-amber);
    border-radius: 14px;
    box-shadow: var(--shadow-card-sm);
    width: 100%;
    margin-bottom: 16px;
    overflow: hidden;
}

/* ─── Header ─── */

.dashboard-briefing-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 20px 0;
}

.dashboard-briefing-header-left {
    display: flex;
    align-items: center;
    gap: 10px;
}

.dashboard-briefing-title {
    font-family: 'Playfair Display', serif;
    font-size: 15px;
    font-weight: 600;
    color: var(--text-primary, #1a1a1a);
    margin: 0;
}

.dashboard-briefing-date {
    font-family: 'Outfit', sans-serif;
    font-size: 12px;
    color: var(--text-secondary, #a1a1aa);
    font-weight: 400;
}

.dashboard-briefing-toggle {
    background: none;
    border: none;
    cursor: pointer;
    color: var(--text-secondary, #a1a1aa);
    padding: 4px;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s ease, color 0.15s ease, transform 0.2s ease;
}

.dashboard-briefing-toggle:hover {
    background: rgba(0, 0, 0, 0.05);
    color: var(--text-primary, #1a1a1a);
}

.dashboard-briefing-toggle.is-collapsed {
    transform: rotate(-90deg);
}

/* ─── Content (stacked layout) ─── */

.dashboard-briefing-body {
    display: flex;
    flex-direction: column;
    padding: 14px 20px 16px;
    gap: 0;
}

/* ─── Divider ─── */

.dashboard-divider {
    height: 1px;
    background: var(--border-card);
    margin: 12px 0;
}

/* ─── Recap Section v2 ─── */

.dashboard-recap-v2 {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.recap-encouragement {
    font-family: 'Lora', serif;
    font-style: italic;
    font-size: 13.5px;
    color: var(--text-secondary, #a1a1aa);
    margin: 0;
    line-height: 1.5;
}

/* ─── Stat Tiles Grid ─── */

.recap-tiles-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 8px;
}

.recap-tile {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    padding: 12px 6px 10px;
    background: var(--bg-secondary, #f5f5f5);
    border-radius: 10px;
    transition: background 0.15s ease, transform 0.15s ease;
}

.recap-tile:hover {
    background: var(--bg-hover, #ebebeb);
    transform: translateY(-1px);
}

.recap-tile-icon {
    color: var(--accent-amber, #f59e0b);
    opacity: 0.8;
    margin-bottom: 2px;
}

.recap-tile-value {
    font-family: 'Playfair Display', serif;
    font-size: 22px;
    font-weight: 700;
    color: var(--text-primary, #1a1a1a);
    font-variant-numeric: tabular-nums;
    line-height: 1.2;
}

.recap-tile-label {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    text-transform: lowercase;
    color: var(--text-muted, #9ca3af);
    letter-spacing: 0.3px;
}

.recap-tile-micro {
    font-family: 'Lora', serif;
    font-size: 10px;
    font-style: italic;
    color: var(--accent-amber, #f59e0b);
    margin-top: 2px;
    text-align: center;
    line-height: 1.3;
}

/* ─── Best Post Card ─── */

.recap-best-post {
    display: flex;
    flex-direction: column;
    gap: 4px;
    padding: 12px 14px;
    background: linear-gradient(135deg, rgba(245, 158, 11, 0.08) 0%, rgba(245, 158, 11, 0.03) 100%);
    border: 1px solid rgba(245, 158, 11, 0.15);
    border-radius: 10px;
    cursor: pointer;
    transition: transform 0.15s ease, box-shadow 0.15s ease;
}

.recap-best-post:hover {
    transform: translateY(-1px);
    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.12);
}

.recap-best-post-badge {
    font-family: 'Outfit', sans-serif;
    font-size: 10px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--accent-amber, #f59e0b);
    display: flex;
    align-items: center;
    gap: 4px;
}

.recap-best-post-title {
    font-family: 'Lora', serif;
    font-size: 14px;
    color: var(--text-primary, #1a1a1a);
    line-height: 1.4;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.recap-best-post-stats {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    color: var(--text-secondary, #a1a1aa);
}

/* ─── Community Highlights ─── */

.recap-community {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.recap-community-label {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.3px;
    color: var(--text-secondary, #a1a1aa);
}

.recap-community-item {
    display: flex;
    align-items: center;
    gap: 8px;
}

.recap-community-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}

.recap-community-text {
    font-family: 'Outfit', sans-serif;
    font-size: 13px;
    color: var(--text-primary, #1a1a1a);
    line-height: 1.4;
}

.recap-community-text strong {
    font-weight: 600;
}

/* ─── Prompt Section ─── */

.dashboard-prompt {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.dashboard-prompt-header {
    display: flex;
    align-items: center;
    gap: 8px;
}

.dashboard-prompt-icon {
    opacity: 0.7;
    color: var(--accent-amber, #f59e0b);
    flex-shrink: 0;
}

.dashboard-prompt-label {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--text-secondary, #a1a1aa);
}

.dashboard-prompt-category {
    font-size: 11px;
    padding: 2px 8px;
    border-radius: 10px;
    background: rgba(212, 168, 83, 0.12);
    color: var(--accent-amber, #f59e0b);
    margin-left: auto;
    font-weight: 500;
}

.dashboard-prompt-text {
    font-family: 'Lora', serif;
    font-size: 18px;
    font-weight: 600;
    line-height: 1.6;
    margin: 0;
    color: var(--text-primary, #1a1a1a);
    border-left: 3px solid var(--accent-amber, #f59e0b);
    padding-left: 14px;
}

.dashboard-prompt-footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    margin-top: 2px;
}

.dashboard-prompt-write-btn {
    padding: 10px 24px;
    border-radius: 20px;
    border: none;
    background: var(--accent-amber, #f59e0b);
    color: #fff;
    font-family: 'Outfit', sans-serif;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s ease;
    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.3);
    display: inline-flex;
    align-items: center;
}

.dashboard-prompt-write-btn:hover {
    background: var(--accent-amber-hover, #d97706);
    transform: translateY(-1px);
    box-shadow: 0 4px 12px rgba(245, 158, 11, 0.35);
}

.dashboard-prompt-write-btn:active {
    transform: translateY(0);
    box-shadow: 0 1px 4px rgba(245, 158, 11, 0.25);
}

.dashboard-prompt-responses {
    display: flex;
    align-items: center;
    gap: 8px;
}

.dashboard-prompt-avatars {
    display: flex;
}

.dashboard-prompt-avatar {
    width: 24px;
    height: 24px;
    border-radius: 50%;
    border: 2px solid var(--bg-card, #fefefe);
    margin-left: -8px;
    object-fit: cover;
}

.dashboard-prompt-avatar:first-child {
    margin-left: 0;
}

.dashboard-prompt-count {
    font-size: 12px;
    color: var(--text-secondary, #a1a1aa);
}

/* ─── Mobile ─── */

@media (max-width: 480px) {
    .dashboard-briefing-body {
        padding: 12px 16px 14px;
    }

    .dashboard-briefing-header {
        padding: 12px 16px 0;
    }

    .dashboard-prompt-text {
        font-size: 15px;
    }

    .recap-tiles-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .recap-tile-value {
        font-size: 18px;
    }

    .recap-tile-micro {
        font-size: 9px;
    }
}

/* ─── Dark mode ─── */

[data-theme="dark"] .dashboard-briefing-toggle:hover {
    background: rgba(255, 255, 255, 0.08);
}

[data-theme="dark"] .dashboard-prompt-write-btn {
    background: var(--accent-amber, #f59e0b);
    color: #1a1a1a;
    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.2);
}

[data-theme="dark"] .dashboard-prompt-write-btn:hover {
    background: var(--accent-amber-hover, #d97706);
    box-shadow: 0 4px 12px rgba(245, 158, 11, 0.25);
}

[data-theme="dark"] .recap-tile {
    background: var(--bg-secondary, #1e1e1e);
}

[data-theme="dark"] .recap-tile:hover {
    background: var(--bg-hover, #2a2a2a);
}

[data-theme="dark"] .recap-best-post {
    background: linear-gradient(135deg, rgba(245, 158, 11, 0.12) 0%, rgba(245, 158, 11, 0.04) 100%);
    border-color: rgba(245, 158, 11, 0.2);
}

