  6→const ReactionButton = ({ userReaction, reactionCount, onReact, disabled }) => {
  7→    const [showPicker, setShowPicker] = useState(false);
  8→    const hoverTimerRef = useRef(null);
  9→    const leaveTimerRef = useRef(null);
 10→    const longPressTimerRef = useRef(null);
 11→    const longPressOpenedRef = useRef(false);
 12→    const isTouchRef = useRef(false);
 13→    const containerRef = useRef(null);
 14→
 15→    const handleMouseEnter = useCallback(() => {
 16→        if (isTouchRef.current) return;
 17→        if (leaveTimerRef.current) {
 18→            clearTimeout(leaveTimerRef.current);
 19→            leaveTimerRef.current = null;
 20→        }
 21→        hoverTimerRef.current = setTimeout(() => {
 22→            setShowPicker(true);
 23→        }, 300);
 24→    }, []);
 25→
 26→    const handleMouseLeave = useCallback(() => {
 27→        if (isTouchRef.current) return;
 28→        if (hoverTimerRef.current) {
 29→            clearTimeout(hoverTimerRef.current);
 30→            hoverTimerRef.current = null;
 31→        }
 32→        leaveTimerRef.current = setTimeout(() => {
 33→            setShowPicker(false);
 34→        }, 150);
 35→    }, []);
 36→
 37→    const handleTouchStart = useCallback(() => {
 38→        isTouchRef.current = true;
 39→        longPressTimerRef.current = setTimeout(() => {
 40→            longPressOpenedRef.current = true;
 41→            setShowPicker(true);
 42→        }, 500);
 43→    }, []);
 44→
 45→    const handleTouchEnd = useCallback(() => {
 46→        if (longPressTimerRef.current) {
 47→            clearTimeout(longPressTimerRef.current);
 48→            longPressTimerRef.current = null;
 49→        }
 50→    }, []);
 51→
 52→    // Tap-outside-to-close for mobile
 53→    useEffect(() => {
 54→        if (!showPicker || !isTouchRef.current) return;
 55→
 56→        const handleOutsideTouch = (e) => {
 57→            if (containerRef.current && !containerRef.current.contains(e.target)) {
 58→                setShowPicker(false);
 59→                isTouchRef.current = false;
 60→            }
 61→        };
 62→
 63→        document.addEventListener('touchstart', handleOutsideTouch);
 64→        return () => document.removeEventListener('touchstart', handleOutsideTouch);
 65→    }, [showPicker]);
 66→
 67→    useEffect(() => {
 68→        return () => {
 69→            if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
 70→            if (leaveTimerRef.current) clearTimeout(leaveTimerRef.current);
 71→            if (longPressTimerRef.current) clearTimeout(longPressTimerRef.current);
 72→        };
 73→    }, []);
 74→
 75→    const handleQuickClick = useCallback((e) => {
 76→        e.preventDefault();
 77→        e.stopPropagation();
 78→        if (disabled) return;
 79→
 80→        if (longPressOpenedRef.current) {
 81→            longPressOpenedRef.current = false;
 82→            return;
 83→        }
 84→
 85→        if (showPicker) {
 86→            setShowPicker(false);
 87→            isTouchRef.current = false;
 88→            return;
 89→        }
 90→
 91→        // Quick tap: toggle heart (or remove current reaction)
 92→        if (userReaction) {
 93→            onReact(userReaction); // toggle off
 94→        } else {
 95→            onReact('heart'); // default to heart
 96→        }
 97→    }, [userReaction, onReact, disabled, showPicker]);
 98→
 99→    const handlePickerSelect = useCallback((reactionType) => {
100→        setShowPicker(false);
101→        isTouchRef.current = false;
102→        onReact(reactionType);
103→    }, [onReact]);
104→
105→    const hasReaction = !!userReaction;
106→    const displayEmoji = hasReaction ? getReactionEmoji(userReaction) : null;
107→
108→    return (
109→        <div
110→            className="reaction-button-container"
111→            ref={containerRef}
112→            onMouseEnter={handleMouseEnter}
113→            onMouseLeave={handleMouseLeave}
114→            onTouchStart={handleTouchStart}
115→            onTouchEnd={handleTouchEnd}
116→        >
117→            <div
118→                className={`reaction-button ${hasReaction ? 'has-reaction' : ''}`}
119→                onClick={handleQuickClick}
120→            >
121→                {hasReaction ? (
122→                    <span className="reaction-button-emoji">{displayEmoji}</span>
123→                ) : (
124→                    <svg className="svg-like" xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
125→                        <g id="style=fill">
126→                        <g id="like">
127→                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M15.9977 5.63891C16.2695 4.34931 15.433 3.00969 14.2102 2.59462C13.6171 2.37633 12.9892 2.4252 12.4662 2.60499C11.9449 2.78419 11.4461 3.12142 11.1369 3.58441L11.136 3.58573L7.49506 9.00272C8.05104 9.29585 8.43005 9.87954 8.43005 10.5518V21.3018H6.91003V21.3018H16.6801C18.2938 21.3018 19.2028 20.2977 19.8943 19.202C20.6524 18.0009 21.1453 16.7211 21.5116 15.5812C21.6808 15.0546 21.8252 14.5503 21.9547 14.0984L21.9863 13.9881C22.126 13.5007 22.2457 13.0904 22.366 12.7549C22.698 11.8292 22.5933 10.9072 22.067 10.2072C21.5476 9.5166 20.7005 9.15175 19.76 9.15175H15.76C15.6702 9.15175 15.6017 9.11544 15.5599 9.06803C15.5238 9.02716 15.4831 8.95058 15.502 8.81171L15.9977 5.63891Z" fill="#5e5e5eff"/>
128→                        <path id="rec" d="M2.18005 10.6199C2.18005 10.03 2.62777 9.55176 3.18005 9.55176H6.68005C7.23234 9.55176 7.68005 10.03 7.68005 10.6199V21.3018H3.18005C2.62777 21.3018 2.18005 20.8235 2.18005 20.2336V10.6199Z" fill="#5e5e5eff"/>
129→                        </g>
130→                        </g>
131→                    </svg>
132→                )}
133→            </div>
134→            {typeof reactionCount === 'number' && reactionCount > 0 && (
135→                <span className="reaction-count">{reactionCount}</span>
136→            )}
137→            <ReactionPicker
